questions.question:
以下のソースコードについて、Dogクラスのsoundメソッドでsuperキーワードを用いて、Animalクラスのsoundメソッドを呼び出すように改修してください。

public class Animal {
    public String sound() {
        return "Generic sound";
    }
}

public class Dog extends Animal {
    @Override
    public String sound() {
        return "Woof!";
    }
}

questions.answer:
public class Dog extends Animal {
    @Override
    public String sound() {
        return super.sound() + ", but also Woof!";
    }
}

public class Main {
    public static void main(String[] args) {
        Animal myDog = new Dog();
        System.out.println(myDog.sound()); // 予想される出力: Generic sound, but also Woof!
    }
}

questions.question:
以下のソースコードについて、DogクラスがインターフェースCanBarkを実装するように改修してください。

public interface CanBark {
    String bark();
}

public class Animal {
    public String sound() {
        return "Generic sound";
    }
}

public class Dog extends Animal {
    @Override
    public String sound() {
        return "Woof!";
    }
}

questions.answer:
public class Dog extends Animal implements CanBark {
    @Override
    public String sound() {
        return "Woof!";
    }

    @Override
    public String bark() {
        return "Bark! Bark!";
    }
}

public class Main {
    public static void main(String[] args) {
        CanBark myDog = new Dog();
        System.out.println(myDog.bark()); // 予想される出力: Bark! Bark!
    }
}

public class Main {
    public static void main(String[] args) {
        // Animalクラスの参照を使用してDogクラスのオブジェクトを参照する
        Animal myDog = new Dog();
        System.out.println(myDog.sound()); // 予想される出力: Woof!
    }
}

